+    public static InputStream utf16Stream(String file, ByteOrder byteOrder)
+            throws IOException {
+        Charset charset;
+        byte[] head;
+        switch (byteOrder) {
+            case BIG_ENDIAN:
+                charset = StandardCharsets.UTF_16BE;
+                head = new byte[] { (byte) 0xFE, (byte) 0xFF };
